### 6. API Endpoints
Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;
using System.Security.Claims;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .ToListAsync();
            return shipments.Select(MapToDto);
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(MapToDto(shipment));
        });

        group.MapGet("/my", async (ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
            var shipments = await db.Shipments
                .Where(s => s.CustomerId == userId)
                .OrderByDescending(s => s.CreatedAt)
                .ToListAsync();
            return shipments.Select(MapToDto);
        });

        group.MapPost("/", async (ShipmentDto dto, ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = string.IsNullOrEmpty(dto.TrackingNumber) 
                    ? GenerateTrackingNumber() 
                    : dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = Enum.TryParse<ShipmentStatus>(dto.Status, out var s) ? s : ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerId = dto.CustomerId ?? user.FindFirstValue(ClaimTypes.NameIdentifier),
                Description = dto.Description
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{shipment.Id}", MapToDto(shipment));
        });

        group.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            if (Enum.TryParse<ShipmentStatus>(request.Status, out var status))
            {
                shipment.Status = status;
                await db.SaveChangesAsync();
                return Results.Ok();
            }
            return Results.BadRequest("Invalid status");
        });
    }

    private static string GenerateTrackingNumber()
        => $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status.ToString(),
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerId = s.CustomerId,
        Description = s.Description
    };
}

public record StatusUpdateRequest(string Status);
```

