        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        if (trackedShipment is null)
            trackingError = "Shipment not found. Please check the tracking number.";
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusColor(string status) => status switch
    {
        "Pending" => "secondary",
        "PickedUp" => "info",
        "InTransit" => "primary",
        "OutForDelivery" => "warning",
        "Delivered" => "success",
        "Cancelled" => "danger",
        _ => "secondary"
    };
}
