@page "/"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Authorize]

<PageTitle>ShipmentTracker - Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track a Shipment</h5>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="Enter tracking number..."
                           @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
                    <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                        Track
                    </button>
                </div>
                @if (trackedShipment is not null)
                {
                    <div class="alert alert-info mt-3">
                        <strong>@trackedShipment.TrackingNumber</strong><br />
                        Status: <span class="badge bg-@GetStatusColor(trackedShipment.Status)">@trackedShipment.Status</span><br />
                        Destination: @trackedShipment.Destination<br />
                        @if (trackedShipment.EstimatedDelivery.HasValue)
                        {
                            <span>Estimated Delivery: @trackedShipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</span>
                        }
                    </div>
                }
                @if (trackingError is not null)
                {
                    <div class="alert alert-warning mt-3">@trackingError</div>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Quick Stats</h5>
                @if (myShipments is not null)
                {
                    <p>Your active shipments: <strong>@myShipments.Count(s => s.Status != "Delivered" && s.Status != "Cancelled")</strong></p>
                    <p>Total shipments: <strong>@myShipments.Count</strong></p>
                }
            </div>
        </div>
    </div>
</div>

<h3>My Shipments</h3>
@if (myShipments is null)
{
    <p><em>Loading...</em></p>
}
else if (!myShipments.Any())
{
    <p>You have no shipments yet.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Estimated Delivery</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in myShipments)
                {
                    <tr>
                        <td>@shipment.TrackingNumber</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? trackedShipment;
    private string? trackingError;
    private List<ShipmentDto>? myShipments;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetMyShipmentsAsync();
    }

    private async Task TrackShipment()
    {
        trackingError = null;
        trackedShipment = null;
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        if (trackedShipment is null)
