</div>

@if (showCreate)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="estimatedDeliveryDate" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Customer ID (optional)</label>
                    <input type="text" class="form-control" @bind="newShipment.CustomerId" placeholder="Leave blank for unassigned" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-2" @onclick="CancelCreate">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="PickedUp">Picked Up</option>
            <option value="InTransit">In Transit</option>
            <option value="OutForDelivery">Out for Delivery</option>
            <option value="Delivered">Delivered</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Created</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CreatedAt.ToString("yyyy-MM-dd")</td>
                        <td>@(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString() ?? shipment.Status)">
                                <option value="Pending">Pending</option>
                                <option value="PickedUp">Picked Up</option>
                                <option value="InTransit">In Transit</option>
                                <option value="OutForDelivery">Out for Delivery</option>
                                <option value="Delivered">Delivered</option>
                                <option value="Cancelled">Cancelled</option>
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool showCreate;
    private ShipmentDto newShipment = new() { Status = "Pending" };
    private DateTime? estimatedDeliveryDate;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments => shipments?
        .Where(s => (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)))
        .Where(s => (string.IsNullOrEmpty(filterStatus) || s.Status == filterStatus))
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        await RefreshShipments();
    }

    private async Task RefreshShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreate = true;
    private void CancelCreate()
    {
        showCreate = false;
        newShipment = new() { Status = "Pending" };
        estimatedDeliveryDate = null;
    }

    private async Task CreateShipment()
    {
        newShipment.EstimatedDelivery = estimatedDeliveryDate;
        await ShipmentService.CreateShipmentAsync(newShipment);
        CancelCreate();
        await RefreshShipments();
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        if (newStatus != shipment.Status)
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusColor(string status) => status switch
    {
        "Pending" => "secondary",
        "PickedUp" => "info",
        "InTransit" => "primary",
        "OutForDelivery" => "warning",
        "Delivered" => "success",
        "Cancelled" => "danger",
        _ => "secondary"
    };
}

